Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange â€” handler that delays so cancellation has time to fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act â€” cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // TestContext.CancellationToken is cancelled when [Timeout] expires
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Lightweight fake â€” no mocking framework needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken,
            Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage canned)
            : this((_, _) => Task.FromResult(canned)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken,
                Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type â€” MSTest awaits them natively |
| **Cancellation** | Pass `TestContext.CancellationToken` so `[Timeout]` can cancel the test |
| **Timeout** | `[Timeout(5000)]` + the cancellation token wired through |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Sealed class** | Performance + design clarity |
| **Constructor-injected TestContext** | Enables `readonly` field, MSTest 3.6+ pattern |

The `FakeHandler` avoids a mocking framework dependency â€” it intercepts `HttpClient.SendAsync` directly, which is the standard pattern for testing `HttpClient`-based code.
